def split(cls, input_datasets, subdir_generator_function, split_params):
    """
    Split the input files by line.
    """
    if not split_params:
        return

    if len(input_datasets) > 1:
        raise Exception("Text file splitting does not support multiple files")
    input_files = [ds.file_name for ds in input_datasets]

    lines_per_file = None
    chunk_size = None
    if split_params['split_mode'] == 'number_of_parts':
        lines_per_file = []

        # Computing the length is expensive!
        def _file_len(fname):
            with open(fname) as f:
                return sum(1 for _ in f)
        length = _file_len(input_files[0])
        parts = int(split_params['split_size'])
        if length < parts:
            parts = length
        len_each, remainder = divmod(length, parts)
        while length > 0:
            chunk = len_each
            if remainder > 0:
                chunk += 1
            lines_per_file.append(chunk)
            remainder -= 1
            length -= chunk
    elif split_params['split_mode'] == 'to_size':
        chunk_size = int(split_params['split_size'])
    else:
        raise Exception(f"Unsupported split mode {split_params['split_mode']}")

    with open(input_files[0]) as f:
        try:
            chunk_idx = 0
            part_file = None
            while True:
                if lines_per_file:
                    this_chunk_size = lines_per_file[chunk_idx] if chunk_idx < len(lines_per_file) else 0
                    chunk_idx += 1
                else:
                    this_chunk_size = chunk_size
                lines_remaining = this_chunk_size
                part_file = None
                while lines_remaining:
                    a_line = f.readline()
                    if not a_line:
                        return
                    if not part_file:
                        part_dir = subdir_generator_function()
                        part_path = os.path.join(part_dir, os.path.basename(input_files[0]))
                        part_file = open(part_path, 'w')
                    part_file.write(a_line)
                    lines_remaining -= 1
        except Exception as e:
            log.error('Unable to split files: %s', unicodify(e))
            raise
        finally:
            if part_file:
                part_file.close()

