def get_pages(item):
    body = parse_html_string(item.get_body_content())
    pages = []

    for elem in body.iter():
        if 'epub:type' in elem.attrib:
            if elem.get('id'):
                _text = elem.text.strip() if elem.text and elem.text.strip() else None

                if not _text:
                    _text = elem.get('aria-label') or get_headers(elem)

                pages.append((item.get_name(), elem.get('id'), _text or elem.get('id')))

    return pages

