def __str__(self):
    name = str(self.name) if hasattr(self, 'name') else ''

    if getattr(self, 'empty', False):
        return ''

    if not self.address and not name:
        return 'EMAIL NOT DEFINED'

    if not self.address and name:
        return name

    if docassemble.base.functions.this_thread.evaluation_context == 'docx':
        return str(self.address)

    if not name and self.address:
        return f'[{str(self.address)}](mailto:{str(self.address)})'

    return f'[{str(name)}](mailto:{str(self.address)})'
